import { BrowserRouter, Routes, Route } from "react-router-dom";

import Navbar from "./components/Navbar";
import ProtectedRoute from "./components/ProtectedRoute";

// Public pages
import Home from "./pages/Home";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Auth from "./pages/Auth";

// Student pages
import StudentDashboard from "./pages/StudentDashboard";
import Books from "./pages/Books";
import BookDetails from "./pages/BooksDetails";
import CategoryBooks from "./pages/CategoryBooks";
import BorrowedBooks from "./pages/BorrowedBooks";
import MyBooks from "./pages/MyBooks";
import Wishlist from "./pages/Wishlist";
import HistoryByCategory from "./pages/HistoryByCategory";
import FineCalculator from "./pages/FineCalculator";

// Librarian pages
import LibrarianDashboard from "./pages/LibrarianDashboard";
import LibrarianInventory from "./pages/LibrarianInventory";
import LibrarianBooks from "./pages/LibrarianBooks";
import AddBook from "./pages/AddBook";
import LibrarianGenreSummary from "./pages/LibrarianGenreSummary";

// Admin pages
import AdminDashboard from "./pages/AdminDashboard";
import AdminManageLibrarians from "./pages/AdminManageLibrarians";
import AdminStudents from "./pages/AdminStudents";
import AdminGenres from "./pages/AdminGenres";
import AdminReports from "./pages/AdminReports";

function App() {
  return (
    <BrowserRouter>
      <Navbar />

      <Routes>
        {/* ===== PUBLIC ROUTES ===== */}
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/auth" element={<Auth />} />

        {/* ===== STUDENT ROUTES ===== */}
        <Route
          path="/student/dashboard"
          element={
            <ProtectedRoute role="Student">
              <StudentDashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/books"
          element={
            <ProtectedRoute role="Student">
              <Books />
            </ProtectedRoute>
          }
        />

        <Route
          path="/book/:title/:author/:cover"
          element={
            <ProtectedRoute role="Student">
              <BookDetails />
            </ProtectedRoute>
          }
        />

        <Route
          path="/category/:name"
          element={
            <ProtectedRoute role="Student">
              <CategoryBooks />
            </ProtectedRoute>
          }
        />

        <Route
          path="/borrowed"
          element={
            <ProtectedRoute role="Student">
              <BorrowedBooks />
            </ProtectedRoute>
          }
        />

        <Route
          path="/mybooks"
          element={
            <ProtectedRoute role="Student">
              <MyBooks />
            </ProtectedRoute>
          }
        />

        <Route
          path="/wishlist"
          element={
            <ProtectedRoute role="Student">
              <Wishlist />
            </ProtectedRoute>
          }
        />

        <Route
          path="/history"
          element={
            <ProtectedRoute role="Student">
              <HistoryByCategory />
            </ProtectedRoute>
          }
        />

        <Route
          path="/fine"
          element={
            <ProtectedRoute role="Student">
              <FineCalculator />
            </ProtectedRoute>
          }
        />

        {/* ===== LIBRARIAN ROUTES ===== */}
        <Route
          path="/librarian/dashboard"
          element={
            <ProtectedRoute role="Librarian">
              <LibrarianDashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/inventory"
          element={
            <ProtectedRoute role="Librarian">
              <LibrarianInventory />
            </ProtectedRoute>
          }
        />

        <Route
          path="/librarian-books"
          element={
            <ProtectedRoute role="Librarian">
              <LibrarianBooks />
            </ProtectedRoute>
          }
        />

        <Route
          path="/add-book"
          element={
            <ProtectedRoute role="Librarian">
              <AddBook />
            </ProtectedRoute>
          }
        />

        <Route
          path="/librarian-genre-summary"
          element={
            <ProtectedRoute role="Librarian">
              <LibrarianGenreSummary />
            </ProtectedRoute>
          }
        />

        {/* ===== ADMIN ROUTES ===== */}
        <Route
          path="/admin/dashboard"
          element={
            <ProtectedRoute role="Admin">
              <AdminDashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/admin/manage-librarians"
          element={
            <ProtectedRoute role="Admin">
              <AdminManageLibrarians />
            </ProtectedRoute>
          }
        />

        <Route
          path="/admin/students"
          element={
            <ProtectedRoute role="Admin">
              <AdminStudents />
            </ProtectedRoute>
          }
        />

        <Route
          path="/admin/genres"
          element={
            <ProtectedRoute role="Admin">
              <AdminGenres />
            </ProtectedRoute>
          }
        />

        <Route
          path="/admin/reports"
          element={
            <ProtectedRoute role="Admin">
              <AdminReports />
            </ProtectedRoute>
          }
        />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
